      'SQL {\n  Statement = SelectStatement ";"?\n\n  SelectStatement\n    = select Distinct? ColumnList from TableRef JoinClause* WhereClause? GroupByClause? HavingClause? OrderByClause? LimitClause? OffsetClause?\n\n  Distinct\n    = distinct on "(" NonemptyListOf<WhereValue, ","> ")"  -- on\n    | distinct                                              -- plain\n\n  // --- Columns ---\n\n  ColumnList = NonemptyListOf<ColumnEntry, ",">\n\n  ColumnEntry\n    = ColumnExpr as identifier  -- aliased\n    | ColumnExpr                -- plain\n\n  ColumnExpr\n    = qualifiedWildcard   -- qualifiedWild\n    | wildcard            -- wild\n    | WhereValue          -- expr\n\n  FuncCall = identifier "(" FuncArgs ")"\n\n  FuncArgs\n    = distinct FuncArgList  -- distinct\n    | FuncArgList           -- plain\n    | wildcard              -- wildcard\n    | /* empty */           -- empty\n\n  FuncArgList = NonemptyListOf<WhereValue, ",">\n\n  qualifiedWildcard = identifier "." "*"\n  wildcard          = "*"\n\n  // --- FROM ---\n\n  TableRef\n    = TableName as identifier  -- aliased\n    | TableName identifier     -- implicitAlias\n    | TableName                -- plain\n\n  TableName\n    = identifier "." identifier  -- qualified\n    | identifier                 -- simple\n\n  // --- JOIN ---\n\n  JoinClause\n    = JoinType join TableRef JoinCondition  -- typed\n    | cross join TableRef                   -- cross\n    | natural join TableRef                 -- natural\n\n  JoinType\n    = inner outer              -- innerOuter\n    | inner                    -- inner\n    | left outer               -- leftOuter\n    | left                     -- left\n    | right outer              -- rightOuter\n    | right                    -- right\n    | full outer               -- fullOuter\n    | full                     -- full\n\n  JoinCondition\n    = on WhereExpr             -- on\n    | using "(" NonemptyListOf<identifier, ","> ")"  -- using\n\n  // --- WHERE ---\n\n  WhereClause = where WhereExpr\n\n  WhereExpr = WhereOrExpr\n\n  WhereOrExpr\n    = WhereOrExpr or WhereAndExpr  -- or\n    | WhereAndExpr\n\n  WhereAndExpr\n    = WhereAndExpr and WherePrimary  -- and\n    | WherePrimary\n\n  WherePrimary\n    = "(" WhereExpr ")"    -- paren\n    | not WherePrimary     -- not\n    | WhereComparison\n\n  WhereComparison\n    = WhereValue compOp WhereValue              -- compare\n    | WhereValue is not null                    -- isNotNull\n    | WhereValue is null                        -- isNull\n    | WhereValue is not boolLiteral             -- isNotBool\n    | WhereValue is boolLiteral                 -- isBool\n    | WhereValue is unknown                     -- isUnknown\n    | WhereValue is not unknown                 -- isNotUnknown\n    | WhereValue not between WhereValue and WhereValue  -- notBetween\n    | WhereValue between WhereValue and WhereValue      -- between\n    | WhereValue not in "(" NonemptyListOf<WhereValue, ","> ")"  -- notIn\n    | WhereValue in "(" NonemptyListOf<WhereValue, ","> ")"      -- in\n    | WhereValue not like WhereValue            -- notLike\n    | WhereValue like WhereValue                -- like\n    | WhereValue not ilike WhereValue           -- notIlike\n    | WhereValue ilike WhereValue               -- ilike\n\n  compOp = "<>" | "!=" | "<=" | ">=" | "<" | ">" | "="\n\n  // Expression hierarchy (lowest to highest precedence)\n  WhereValue = AddExpr\n\n  AddExpr\n    = AddExpr "+" MulExpr   -- add\n    | AddExpr "-" MulExpr   -- sub\n    | AddExpr "||" MulExpr  -- concat\n    | MulExpr\n\n  MulExpr\n    = MulExpr "*" UnaryExpr  -- mul\n    | MulExpr "/" UnaryExpr  -- div\n    | MulExpr "%" UnaryExpr  -- mod\n    | UnaryExpr\n\n  UnaryExpr\n    = "-" AtomExpr           -- neg\n    | AtomExpr\n\n  AtomExpr\n    = FuncCall               -- func\n    | "(" WhereValue ")"     -- paren\n    | stringLiteral          -- string\n    | floatLiteral           -- float\n    | integer                -- integer\n    | boolLiteral            -- bool\n    | null                   -- null\n    | ColumnRef              -- columnRef\n\n  ColumnRef\n    = identifier "." identifier  -- qualified\n    | identifier                 -- simple\n\n  stringLiteral = "\'" (~"\'" any)* "\'"\n  floatLiteral  = digit+ "." digit+\n\n  boolLiteral = (caseInsensitive<"true"> | caseInsensitive<"false">) ~identPart\n\n  // --- GROUP BY / HAVING ---\n\n  GroupByClause = group by NonemptyListOf<WhereValue, ",">\n\n  HavingClause = having WhereExpr\n\n  // --- ORDER BY ---\n\n  OrderByClause = order by NonemptyListOf<OrderByItem, ",">\n\n  OrderByItem = WhereValue OrderDirection? NullsOrder?\n\n  OrderDirection\n    = asc   -- asc\n    | desc  -- desc\n\n  NullsOrder\n    = nulls first  -- first\n    | nulls last   -- last\n\n  // --- LIMIT / OFFSET ---\n\n  LimitClause = limit integer\n  OffsetClause = offset integer\n\n  // --- Terminals ---\n\n  identifier = ~keyword letter (alnum | "_")*\n  integer    = digit+\n\n  // --- Keywords (case-insensitive) ---\n\n  select = caseInsensitive<"select"> ~identPart\n  from   = caseInsensitive<"from">   ~identPart\n  as     = caseInsensitive<"as">     ~identPart\n  where  = caseInsensitive<"where">  ~identPart\n  and    = caseInsensitive<"and">    ~identPart\n  or     = caseInsensitive<"or">     ~identPart\n  limit  = caseInsensitive<"limit">  ~identPart\n  not     = caseInsensitive<"not">     ~identPart\n  null    = caseInsensitive<"null">    ~identPart\n  is      = caseInsensitive<"is">      ~identPart\n  join    = caseInsensitive<"join">    ~identPart\n  inner   = caseInsensitive<"inner">   ~identPart\n  left    = caseInsensitive<"left">    ~identPart\n  right   = caseInsensitive<"right">   ~identPart\n  full    = caseInsensitive<"full">    ~identPart\n  outer   = caseInsensitive<"outer">   ~identPart\n  cross   = caseInsensitive<"cross">   ~identPart\n  natural = caseInsensitive<"natural"> ~identPart\n  on      = caseInsensitive<"on">      ~identPart\n  using   = caseInsensitive<"using">   ~identPart\n  order   = caseInsensitive<"order">   ~identPart\n  by      = caseInsensitive<"by">      ~identPart\n  group    = caseInsensitive<"group">    ~identPart\n  having   = caseInsensitive<"having">  ~identPart\n  distinct = caseInsensitive<"distinct"> ~identPart\n  asc     = caseInsensitive<"asc">     ~identPart\n  desc    = caseInsensitive<"desc">    ~identPart\n  nulls   = caseInsensitive<"nulls">   ~identPart\n  first   = caseInsensitive<"first">   ~identPart\n  last    = caseInsensitive<"last">    ~identPart\n  offset   = caseInsensitive<"offset">   ~identPart\n  between  = caseInsensitive<"between">  ~identPart\n  in       = caseInsensitive<"in">       ~identPart\n  like     = caseInsensitive<"like">     ~identPart\n  ilike    = caseInsensitive<"ilike">    ~identPart\n  unknown  = caseInsensitive<"unknown">  ~identPart\n\n  keyword = select | from | as | where | and | or | limit | not | null | is\n          | join | inner | left | right | full | outer | cross | natural | on | using\n          | order | by | asc | desc | nulls | first | last | offset | group | having | distinct\n          | between | in | like | ilike | unknown\n  identPart = alnum | "_"\n\n  // --- Comments & whitespace ---\n\n  space += lineComment\n  lineComment = "--" (~"\\n" any)*\n}',
